<?php
 namespace League\CommonMark\Node; abstract class Node { protected $depth = 0; protected $parent; protected $previous; protected $next; protected $firstChild; protected $lastChild; public function previous(): ?Node { return $this->previous; } public function next(): ?Node { return $this->next; } public function parent(): ?Node { return $this->parent; } protected function setParent(Node $node = null) { $this->parent = $node; $this->depth = ($node === null) ? 0 : $node->depth + 1; } public function insertAfter(Node $sibling) { $sibling->detach(); $sibling->next = $this->next; if ($sibling->next) { $sibling->next->previous = $sibling; } $sibling->previous = $this; $this->next = $sibling; $sibling->setParent($this->parent); if (!$sibling->next && $sibling->parent) { $sibling->parent->lastChild = $sibling; } } public function insertBefore(Node $sibling) { $sibling->detach(); $sibling->previous = $this->previous; if ($sibling->previous) { $sibling->previous->next = $sibling; } $sibling->next = $this; $this->previous = $sibling; $sibling->setParent($this->parent); if (!$sibling->previous && $sibling->parent) { $sibling->parent->firstChild = $sibling; } } public function replaceWith(Node $replacement) { $replacement->detach(); $this->insertAfter($replacement); $this->detach(); } public function detach() { if ($this->previous) { $this->previous->next = $this->next; } elseif ($this->parent) { $this->parent->firstChild = $this->next; } if ($this->next) { $this->next->previous = $this->previous; } elseif ($this->parent) { $this->parent->lastChild = $this->previous; } $this->parent = null; $this->next = null; $this->previous = null; $this->depth = 0; } abstract public function isContainer(): bool; public function firstChild(): ?Node { return $this->firstChild; } public function lastChild(): ?Node { return $this->lastChild; } public function children(): iterable { $children = []; for ($current = $this->firstChild; null !== $current; $current = $current->next) { $children[] = $current; } return $children; } public function appendChild(Node $child) { if ($this->lastChild) { $this->lastChild->insertAfter($child); } else { $child->detach(); $child->setParent($this); $this->lastChild = $this->firstChild = $child; } } public function prependChild(Node $child) { if ($this->firstChild) { $this->firstChild->insertBefore($child); } else { $child->detach(); $child->setParent($this); $this->lastChild = $this->firstChild = $child; } } public function detachChildren() { foreach ($this->children() as $children) { $children->setParent(null); } $this->firstChild = $this->lastChild = null; } public function replaceChildren(iterable $children) { $this->detachChildren(); foreach ($children as $item) { $this->appendChild($item); } return $this; } public function getDepth(): int { return $this->depth; } public function walker(): NodeWalker { return new NodeWalker($this); } public function __clone() { $this->parent = null; $this->previous = null; $this->next = null; $children = $this->children(); $this->detachChildren(); foreach ($children as $child) { $this->appendChild(clone $child); } } } 